import{_ as e,o as l,c as a,a2 as n}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"F04: 業外收支純度與收益質量 — 投資研究員審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/8103_瀚荃/20260425/F04_業外收支純度與收益質量.md","filePath":"審計報告庫/財務審計/8103_瀚荃/20260425/F04_業外收支純度與收益質量.md"}'),i={name:"審計報告庫/財務審計/8103_瀚荃/20260425/F04_業外收支純度與收益質量.md"};function d(s,t,r,o,g,h){return l(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="f04-業外收支純度與收益質量-—-投資研究員審計報告" tabindex="-1">F04: 業外收支純度與收益質量 — 投資研究員審計報告 <a class="header-anchor" href="#f04-業外收支純度與收益質量-—-投資研究員審計報告" aria-label="Permalink to &quot;F04: 業外收支純度與收益質量 — 投資研究員審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>業外收支 (Non-Operating) 規模與組成細項為何？是長期投資收益還是匯兌/利息等雜項損益？是否存在獲利虛胖風險？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>2025 年業外佔稅前淨利僅 7.2%，本業獲利純度<strong>高</strong>，採<strong>積極</strong>觀點。2024 年業外佔比達 27.7%，主因匯兌利益佔淨利 22.2%，屬短期匯率紅利。2025 年匯兌歸零，結構回歸利息+租金+補助收益之定常性組合，獲利品質顯著改善。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>A (良)</strong> — 業外結構以利息收入為主體，2025 年匯兌利益歸零後無重大匯兌損失或衍生工具評價風險。2024 年雖因匯兌利益佔淨利 22.2% 而觸及「獲利含金量極低」警訊門檻，但 2025 年結構已修正回歸常態。權益法投資規模極小（僅 6.3 百萬元，佔總資產 0.1%），不存在「投資公司化」之治理警訊。</p><hr><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-收益結構透視-income-composition" tabindex="-1">1. 收益結構透視 (Income Composition) <a class="header-anchor" href="#_1-收益結構透視-income-composition" aria-label="Permalink to &quot;1. 收益結構透視 (Income Composition)&quot;">​</a></h3><p><strong>近三年業外收支總量對比：</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">年度</th><th style="text-align:left;">業外收支(千元)</th><th style="text-align:left;">稅前淨利(千元)</th><th style="text-align:left;">業外佔比</th></tr></thead><tbody><tr><td style="text-align:left;">2023</td><td style="text-align:left;">44,165</td><td style="text-align:left;">341,224</td><td style="text-align:left;">12.9%</td></tr><tr><td style="text-align:left;">2024</td><td style="text-align:left;">139,804</td><td style="text-align:left;">504,452</td><td style="text-align:left;">27.7%</td></tr><tr><td style="text-align:left;">2025</td><td style="text-align:left;">34,851</td><td style="text-align:left;">484,315</td><td style="text-align:left;">7.2%</td></tr></tbody></table><p><strong>2024 年業外出三大細項</strong>：外幣兌換利益 75 百萬（佔淨利 22.2%，年度最大來源）、利息收入 62 百萬、其他收入 70 百萬（租金+補助）。<strong>2025 年業外出三大細項</strong>：利息收入 48 百萬、其他收入 57 百萬（含租金 2、補助 6、處分投資利益 11）、匯兌利益 0。</p><p><strong>單季業外波動：</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">季度</th><th style="text-align:left;">業外(千元)</th><th style="text-align:left;">佔稅前淨利比</th><th style="text-align:left;">備註</th></tr></thead><tbody><tr><td style="text-align:left;">2024Q1</td><td style="text-align:left;">+78,560</td><td style="text-align:left;">+65.0%</td><td style="text-align:left;">匯兌大舉挹注</td></tr><tr><td style="text-align:left;">2024Q2</td><td style="text-align:left;">+48,466</td><td style="text-align:left;">+28.1%</td><td style="text-align:left;">匯兌持續</td></tr><tr><td style="text-align:left;">2024Q3</td><td style="text-align:left;">-63,034</td><td style="text-align:left;">-80.8%</td><td style="text-align:left;">匯兌侵蝕本業</td></tr><tr><td style="text-align:left;">2024Q4</td><td style="text-align:left;">+75,812</td><td style="text-align:left;">+57.0%</td><td style="text-align:left;">匯兌轉正</td></tr><tr><td style="text-align:left;">2025Q1</td><td style="text-align:left;">+24,943</td><td style="text-align:left;">+27.3%</td><td style="text-align:left;">匯兌縮小</td></tr><tr><td style="text-align:left;">2025Q2</td><td style="text-align:left;">-49,248</td><td style="text-align:left;">-54.2%</td><td style="text-align:left;">匯兌損失</td></tr><tr><td style="text-align:left;">2025Q3</td><td style="text-align:left;">+19,380</td><td style="text-align:left;">+12.2%</td><td style="text-align:left;">回歸常態</td></tr><tr><td style="text-align:left;">2025Q4</td><td style="text-align:left;">+39,776</td><td style="text-align:left;">+27.9%</td><td style="text-align:left;">含投資處分 11 百萬</td></tr></tbody></table><h3 id="_2-雜訊敏感度分析-noise-sensitivity" tabindex="-1">2. 雜訊敏感度分析 (Noise Sensitivity) <a class="header-anchor" href="#_2-雜訊敏感度分析-noise-sensitivity" aria-label="Permalink to &quot;2. 雜訊敏感度分析 (Noise Sensitivity)&quot;">​</a></h3><p>瀚荃業外核心變數為「外幣兌換損益」。海外營收佔比高，跨國基地遍及中國、越南、泰國，匯率波動直接穿透損益表：</p><ul><li><strong>2024Q1 匯兌利益 64 百萬 vs 2024Q3 匯兌損失</strong>：單季由 +78,560 千翻轉至 -63,034 千，波動達 1.42 億（當季營業利益 44.7%）。匯率每變動 1%，邊際影響稅前淨利約 3-5%。</li><li><strong>2025 年匯兌歸零</strong>：台幣趨穩或公司已加強自然避險。</li></ul><p><strong>利息收入穩定性</strong>：現金部位長期維持 20-26 億元，年利息 48-62 百萬，年化報酬 2.0-2.4%，為低風險定常性收益。</p><h3 id="_3-可持續性評價-sustainability-audit" tabindex="-1">3. 可持續性評價 (Sustainability Audit) <a class="header-anchor" href="#_3-可持續性評價-sustainability-audit" aria-label="Permalink to &quot;3. 可持續性評價 (Sustainability Audit)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">業外項目</th><th style="text-align:left;">定常性</th><th style="text-align:left;">未來三季機率</th></tr></thead><tbody><tr><td style="text-align:left;">利息收入</td><td style="text-align:left;">高</td><td style="text-align:left;">&gt;95%</td></tr><tr><td style="text-align:left;">租金收入</td><td style="text-align:left;">高</td><td style="text-align:left;">&gt;90%</td></tr><tr><td style="text-align:left;">補助收益</td><td style="text-align:left;">中</td><td style="text-align:left;">&gt;60%</td></tr><tr><td style="text-align:left;">外幣兌換利益</td><td style="text-align:left;">低</td><td style="text-align:left;">&lt;30%</td></tr><tr><td style="text-align:left;">處分投資利益</td><td style="text-align:left;">極低</td><td style="text-align:left;">&lt;10%</td></tr></tbody></table><p><strong>扣非後 EPS 估算</strong>：2024 年 EPS 4.00 元，扣除匯兌 75 百萬+公允價值 2 百萬後調整約 3.10 元；2025 年 EPS 3.96 元，業外以定常性為主，調整後約 3.82 元。<strong>結論</strong>：2025 年 EPS 品質遠優於 2024 年。</p><hr><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><h3 id="公允價值變動損益風險預警" tabindex="-1">公允價值變動損益風險預警 <a class="header-anchor" href="#公允價值變動損益風險預警" aria-label="Permalink to &quot;公允價值變動損益風險預警&quot;">​</a></h3><p>瀚荃持有「透過損益按公允價值衡量之金融資產」（流動 + 非流動），2023Q1 餘額約 22 百萬元，佔總資產僅 0.4%。2024 全年公允價值利益僅 2 百萬元，佔淨利 0.6%，規模極小。此類金融資產不構成「未實現風險」之重大威脅。</p><h3 id="匯兌損益的深層解讀" tabindex="-1">匯兌損益的深層解讀 <a class="header-anchor" href="#匯兌損益的深層解讀" aria-label="Permalink to &quot;匯兌損益的深層解讀&quot;">​</a></h3><p>2024 年瀚荃的匯兌利益 75 百萬，本質上是「台幣貶值紅利」。2024 年台幣對美元匯率從 31.5 貶至 32.5 區間，瀚荃以美元計價的應收帳款產生未實現評價收益。但這類收益的致命缺陷是：</p><ol><li><strong>無現金流入</strong> — 匯兌利益多數為帳面評價，不等同現金股利或利息</li><li><strong>完全可逆</strong> — 2024Q3 台幣反彈時，匯兌利益瞬間翻為損失，單季吞掉 63 百萬</li><li><strong>不可複製</strong> — 2025 年台幣匯率持穩，匯兌利益歸零</li></ol><p><strong>判定</strong>：2024 年匯兌利益屬於「短期性套利 (Short-term Arbitrage)」，非「戰略性穩健 (Strategic Stability)」。</p><h3 id="權益法投資質地" tabindex="-1">權益法投資質地 <a class="header-anchor" href="#權益法投資質地" aria-label="Permalink to &quot;權益法投資質地&quot;">​</a></h3><p>瀚荃權益法投資從 2023Q3 首度出現（5.2 百萬），高峰至 2024Q2 的 9.0 百萬後逐步縮減至 2025Q4 的 6.3 百萬。規模僅佔總資產 0.1%，對損益影響微乎其微，不構成治理風險。</p><h3 id="本業獲利結構正向演化" tabindex="-1">本業獲利結構正向演化 <a class="header-anchor" href="#本業獲利結構正向演化" aria-label="Permalink to &quot;本業獲利結構正向演化&quot;">​</a></h3><p>2025 年營業利益 449,464 千元，年增 23.2%，且佔稅前淨利比重回升至 92.8%。這代表公司 AI 伺服器連接器業務的成長動能已實質轉化為本業獲利，業外只是錦上添花，而非遮掩本業虧損的遮羞布。</p><hr><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ol><li><strong>FinMind</strong> — <code>TaiwanStockFinancialStatements</code> (8103, 2023Q1~2025Q4)，提取 TotalNonoperatingIncomeAndExpense、OperatingIncome、PreTaxIncome、NetIncome、EPS</li><li><strong>FinMind</strong> — <code>TaiwanStockBalanceSheet</code> (8103, 2023Q1~2025Q4)，提取 InvestmentAccountedForUsingEquityMethod、CurrentFinancialAssetsAtFairvalueThroughProfitOrLoss</li><li><strong>MoneyDJ 綜合損益表累計季表</strong> — 瀚荃 (8103) 2024Q1~2025Q4 業外細項：利息收入、租金收入、補助收益、外幣兌換利益、透過損益按公允價值衡量之金融資產利益、處分投資利益</li><li><strong>FinMind</strong> — <code>TaiwanStockCashFlowsStatement</code> (8103)，提取 InterestIncome、InterestExpense</li><li><strong>計算腳本</strong> — <code>/tmp/calc_all.py</code>（業外佔比、扣非 EPS、匯兌佔淨利比等計算）</li></ol><hr><p><strong>審計身分</strong>：Deep32Q L3 投資研究員 <strong>審計日期</strong>：2026-04-25 <strong>數據時效</strong>：截至 2025Q4 最新公開財報</p>',39)])])}const y=e(i,[["render",d]]);export{x as __pageData,y as default};
